import{_ as t,o as d,c as o,ag as a}from"./chunks/framework.BBBcTwIo.js";const m=JSON.parse('{"title":"State Management","description":"","frontmatter":{},"headers":[],"relativePath":"state-management.md","filePath":"state-management.md"}'),i={name:"state-management.md"};function c(r,e,n,l,s,h){return d(),o("div",null,[...e[0]||(e[0]=[a(`<h1 id="state-management" tabindex="-1">State Management <a class="header-anchor" href="#state-management" aria-label="Permalink to &quot;State Management&quot;">​</a></h1><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>DYO uses <strong>Zustand 5</strong> as the single source of truth for all design state. The main store (<code>lib/headstone-store.ts</code>, ~2000+ LOC) is consumed by both React UI components and Three.js scene components.</p><p>A secondary store (<code>lib/scene-overlay-store.ts</code>) manages floating panel UI state.</p><h2 id="main-store-useheadstonestore" tabindex="-1">Main Store: <code>useHeadstoneStore</code> <a class="header-anchor" href="#main-store-useheadstonestore" aria-label="Permalink to &quot;Main Store: \`useHeadstoneStore\`&quot;">​</a></h2><h3 id="state-slices" tabindex="-1">State Slices <a class="header-anchor" href="#state-slices" aria-label="Permalink to &quot;State Slices&quot;">​</a></h3><h4 id="product-catalog" tabindex="-1">Product &amp; Catalog <a class="header-anchor" href="#product-catalog" aria-label="Permalink to &quot;Product &amp; Catalog&quot;">​</a></h4><table tabindex="0"><thead><tr><th>State</th><th>Type</th><th>Purpose</th></tr></thead><tbody><tr><td><code>catalog</code></td><td><code>CatalogData</code></td><td>Parsed XML product catalog</td></tr><tr><td><code>productId</code></td><td><code>string</code></td><td>Current product type ID</td></tr><tr><td><code>materials</code></td><td><code>Material[]</code></td><td>Available material options</td></tr><tr><td><code>shapes</code></td><td><code>Shape[]</code></td><td>Available headstone shapes</td></tr><tr><td><code>borders</code></td><td><code>BorderOption[]</code></td><td>Available border options</td></tr><tr><td><code>motifsCatalog</code></td><td><code>MotifCatalogItem[]</code></td><td>Available motif library</td></tr></tbody></table><h4 id="dimensions-all-in-mm" tabindex="-1">Dimensions (all in mm) <a class="header-anchor" href="#dimensions-all-in-mm" aria-label="Permalink to &quot;Dimensions (all in mm)&quot;">​</a></h4><table tabindex="0"><thead><tr><th>State</th><th>Type</th><th>Purpose</th></tr></thead><tbody><tr><td><code>widthMm</code></td><td><code>number</code></td><td>Headstone width</td></tr><tr><td><code>heightMm</code></td><td><code>number</code></td><td>Headstone height</td></tr><tr><td><code>minWidthMm</code> / <code>maxWidthMm</code></td><td><code>number</code></td><td>Width constraints (300–1200)</td></tr><tr><td><code>minHeightMm</code> / <code>maxHeightMm</code></td><td><code>number</code></td><td>Height constraints (300–1200)</td></tr><tr><td><code>baseWidthMm</code> / <code>baseHeightMm</code></td><td><code>number</code></td><td>Base pedestal dimensions</td></tr><tr><td><code>baseThickness</code> / <code>uprightThickness</code> / <code>slantThickness</code></td><td><code>number</code></td><td>Thickness values</td></tr><tr><td><code>ledgerWidthMm</code> / <code>ledgerDepthMm</code> / <code>ledgerHeightMm</code></td><td><code>number</code></td><td>Ledger slab (full monument)</td></tr><tr><td><code>kerbWidthMm</code> / <code>kerbHeightMm</code> / <code>kerbDepthMm</code></td><td><code>number</code></td><td>Kerbset border (full monument)</td></tr></tbody></table><h4 id="materials-textures" tabindex="-1">Materials &amp; Textures <a class="header-anchor" href="#materials-textures" aria-label="Permalink to &quot;Materials &amp; Textures&quot;">​</a></h4><table tabindex="0"><thead><tr><th>State</th><th>Type</th><th>Purpose</th></tr></thead><tbody><tr><td><code>materialUrl</code></td><td><code>string</code></td><td>Generic material URL</td></tr><tr><td><code>headstoneMaterialUrl</code></td><td><code>string</code></td><td>Headstone face texture path</td></tr><tr><td><code>baseMaterialUrl</code></td><td><code>string</code></td><td>Base pedestal texture path</td></tr><tr><td><code>ledgerMaterialUrl</code></td><td><code>string</code></td><td>Ledger slab texture path</td></tr><tr><td><code>kerbsetMaterialUrl</code></td><td><code>string</code></td><td>Kerbset border texture path</td></tr><tr><td><code>baseSwapping</code></td><td><code>boolean</code></td><td>Whether base material can differ from headstone</td></tr></tbody></table><h4 id="inscriptions" tabindex="-1">Inscriptions <a class="header-anchor" href="#inscriptions" aria-label="Permalink to &quot;Inscriptions&quot;">​</a></h4><table tabindex="0"><thead><tr><th>State</th><th>Type</th><th>Purpose</th></tr></thead><tbody><tr><td><code>inscriptions</code></td><td><code>Line[]</code></td><td>Array of text lines</td></tr><tr><td><code>selectedInscriptionId</code></td><td><code>string | null</code></td><td>Currently selected text line</td></tr><tr><td><code>activeInscriptionText</code></td><td><code>string</code></td><td>Text being edited</td></tr><tr><td><code>fontLoading</code></td><td><code>boolean</code></td><td>Font loading state</td></tr></tbody></table><p>Each <code>Line</code> has: <code>id</code>, <code>text</code>, <code>height</code> (mm), <code>font</code>, <code>color</code>, <code>xPos</code>, <code>yPos</code>, <code>rotationDeg</code>, <code>surface</code>.</p><h4 id="motifs" tabindex="-1">Motifs <a class="header-anchor" href="#motifs" aria-label="Permalink to &quot;Motifs&quot;">​</a></h4><table tabindex="0"><thead><tr><th>State</th><th>Type</th><th>Purpose</th></tr></thead><tbody><tr><td><code>selectedMotifs</code></td><td><code>Motif[]</code></td><td>Array of placed motifs</td></tr><tr><td><code>selectedMotifId</code></td><td><code>string | null</code></td><td>Currently selected motif</td></tr><tr><td><code>motifOffsets</code></td><td><code>Record&lt;id, MotifOffset&gt;</code></td><td>Position/scale/rotation per motif</td></tr><tr><td><code>motifRefs</code></td><td><code>Record&lt;id, Ref&gt;</code></td><td>Three.js mesh refs</td></tr><tr><td><code>motifPriceModel</code></td><td><code>PricingModel</code></td><td>Pricing formula data</td></tr></tbody></table><p>Each <code>MotifOffset</code> has: <code>xPos</code>, <code>yPos</code>, <code>scale</code>, <code>rotationZ</code>, <code>heightMm</code>.</p><h4 id="additions" tabindex="-1">Additions <a class="header-anchor" href="#additions" aria-label="Permalink to &quot;Additions&quot;">​</a></h4><table tabindex="0"><thead><tr><th>State</th><th>Type</th><th>Purpose</th></tr></thead><tbody><tr><td><code>selectedAdditions</code></td><td><code>Addition[]</code></td><td>Array of placed 3D objects</td></tr><tr><td><code>selectedAdditionId</code></td><td><code>string | null</code></td><td>Currently selected addition</td></tr><tr><td><code>additionOffsets</code></td><td><code>Record&lt;id, AdditionOffset&gt;</code></td><td>Position per addition</td></tr><tr><td><code>additionRefs</code></td><td><code>Record&lt;id, Ref&gt;</code></td><td>Three.js mesh refs</td></tr></tbody></table><h4 id="emblems" tabindex="-1">Emblems <a class="header-anchor" href="#emblems" aria-label="Permalink to &quot;Emblems&quot;">​</a></h4><table tabindex="0"><thead><tr><th>State</th><th>Type</th><th>Purpose</th></tr></thead><tbody><tr><td><code>selectedEmblems</code></td><td><code>Emblem[]</code></td><td>Array of placed emblems</td></tr><tr><td><code>selectedEmblemId</code></td><td><code>string | null</code></td><td>Currently selected emblem</td></tr><tr><td><code>emblemOffsets</code></td><td><code>Record&lt;id, EmblemOffset&gt;</code></td><td>Position/scale per emblem</td></tr></tbody></table><h4 id="images" tabindex="-1">Images <a class="header-anchor" href="#images" aria-label="Permalink to &quot;Images&quot;">​</a></h4><table tabindex="0"><thead><tr><th>State</th><th>Type</th><th>Purpose</th></tr></thead><tbody><tr><td><code>selectedImages</code></td><td><code>Image[]</code></td><td>Array of placed photos</td></tr><tr><td><code>selectedImageId</code></td><td><code>string | null</code></td><td>Currently selected image</td></tr><tr><td><code>cropCanvasData</code></td><td><code>CropData</code></td><td>Active crop operation state</td></tr></tbody></table><h4 id="pricing" tabindex="-1">Pricing <a class="header-anchor" href="#pricing" aria-label="Permalink to &quot;Pricing&quot;">​</a></h4><table tabindex="0"><thead><tr><th>State</th><th>Type</th><th>Purpose</th></tr></thead><tbody><tr><td><code>inscriptionCost</code></td><td><code>number</code></td><td>Calculated inscription total</td></tr><tr><td><code>motifCost</code></td><td><code>number</code></td><td>Calculated motif total</td></tr><tr><td><code>emblemCost</code></td><td><code>number</code></td><td>Calculated emblem total</td></tr><tr><td><code>imageCost</code></td><td><code>number</code></td><td>Calculated image total</td></tr><tr><td><code>additionCost</code></td><td><code>number</code></td><td>Calculated addition total</td></tr></tbody></table><h4 id="ui-state" tabindex="-1">UI State <a class="header-anchor" href="#ui-state" aria-label="Permalink to &quot;UI State&quot;">​</a></h4><table tabindex="0"><thead><tr><th>State</th><th>Type</th><th>Purpose</th></tr></thead><tbody><tr><td><code>activePanel</code></td><td><code>string</code></td><td>Currently active sidebar section</td></tr><tr><td><code>selected</code></td><td><code>&#39;headstone&#39; | &#39;base&#39; | &#39;ledger&#39; | &#39;kerbset&#39; | null</code></td><td>Selected monument part</td></tr><tr><td><code>editingObject</code></td><td><code>object | null</code></td><td>Object being edited</td></tr><tr><td><code>showBase</code></td><td><code>boolean</code></td><td>Base visibility</td></tr><tr><td><code>showLedger</code></td><td><code>boolean</code></td><td>Ledger visibility (full monument)</td></tr><tr><td><code>showKerbset</code></td><td><code>boolean</code></td><td>Kerbset visibility (full monument)</td></tr><tr><td><code>is2DMode</code></td><td><code>boolean</code></td><td>2D vs 3D view toggle</td></tr><tr><td><code>loading</code></td><td><code>boolean</code></td><td>Global loading indicator</td></tr></tbody></table><h4 id="design-metadata" tabindex="-1">Design Metadata <a class="header-anchor" href="#design-metadata" aria-label="Permalink to &quot;Design Metadata&quot;">​</a></h4><table tabindex="0"><thead><tr><th>State</th><th>Type</th><th>Purpose</th></tr></thead><tbody><tr><td><code>currentProjectId</code></td><td><code>string | null</code></td><td>Saved project ID</td></tr><tr><td><code>currentProjectTitle</code></td><td><code>string</code></td><td>Project display name</td></tr><tr><td><code>shapeUrl</code></td><td><code>string</code></td><td>Current shape SVG path</td></tr><tr><td><code>borderName</code></td><td><code>string</code></td><td>Current border selection</td></tr><tr><td><code>headstoneStyle</code></td><td><code>string</code></td><td>Engraving style (laser/traditional)</td></tr></tbody></table><h3 id="key-actions" tabindex="-1">Key Actions <a class="header-anchor" href="#key-actions" aria-label="Permalink to &quot;Key Actions&quot;">​</a></h3><h4 id="product-setup" tabindex="-1">Product Setup <a class="header-anchor" href="#product-setup" aria-label="Permalink to &quot;Product Setup&quot;">​</a></h4><ul><li><code>setProductId(id)</code> — Loads catalog XML, configures visibility &amp; dimension constraints</li></ul><h4 id="inscription-crud" tabindex="-1">Inscription CRUD <a class="header-anchor" href="#inscription-crud" aria-label="Permalink to &quot;Inscription CRUD&quot;">​</a></h4><ul><li><code>addInscriptionLine(patch)</code> — Add new text line</li><li><code>updateInscription(id, patch)</code> — Update text, font, size, color, position</li><li><code>duplicateInscription(id)</code> — Clone a text line</li><li><code>deleteInscription(id)</code> — Remove a text line</li><li><code>setSelectedInscriptionId(id)</code> — Select for editing</li></ul><h4 id="motif-crud" tabindex="-1">Motif CRUD <a class="header-anchor" href="#motif-crud" aria-label="Permalink to &quot;Motif CRUD&quot;">​</a></h4><ul><li><code>addMotif(svgPath)</code> — Place new motif on surface</li><li><code>removeMotif(id)</code> — Remove motif</li><li><code>setMotifColor(id, color)</code> — Change motif color</li><li><code>setMotifOffset(id, offset)</code> — Update position/scale</li><li><code>duplicateMotif(id)</code> — Clone a motif</li></ul><h4 id="addition-crud" tabindex="-1">Addition CRUD <a class="header-anchor" href="#addition-crud" aria-label="Permalink to &quot;Addition CRUD&quot;">​</a></h4><ul><li><code>addAddition(id)</code> — Place new 3D object</li><li><code>removeAddition(id)</code> — Remove object</li><li><code>setAdditionOffset(id, offset)</code> — Update position</li><li><code>duplicateAddition(id)</code> — Clone an addition</li></ul><h4 id="emblem-crud" tabindex="-1">Emblem CRUD <a class="header-anchor" href="#emblem-crud" aria-label="Permalink to &quot;Emblem CRUD&quot;">​</a></h4><ul><li><code>addEmblem(emblemId, imageUrl)</code> — Place new emblem</li><li><code>removeEmblem(id)</code> — Remove emblem</li><li><code>duplicateEmblem(id)</code> — Clone emblem</li><li><code>setEmblemOffset(id, offset)</code> — Update position/scale</li></ul><h4 id="image-crud" tabindex="-1">Image CRUD <a class="header-anchor" href="#image-crud" aria-label="Permalink to &quot;Image CRUD&quot;">​</a></h4><ul><li><code>addImage(image)</code> — Place photo</li><li><code>removeImage(id)</code> — Remove photo</li><li><code>updateImagePosition(id, ...)</code> / <code>updateImageSize(id, ...)</code> / <code>updateImageRotation(id, ...)</code> — Edit</li><li><code>duplicateImage(id)</code> — Clone image</li></ul><h4 id="pricing-1" tabindex="-1">Pricing <a class="header-anchor" href="#pricing-1" aria-label="Permalink to &quot;Pricing&quot;">​</a></h4><ul><li><code>calculateInscriptionCost()</code> — Aggregate inscription pricing</li><li><code>calculateMotifCost()</code> — Aggregate motif pricing</li><li><code>calculateImageCost()</code> — Aggregate image pricing</li><li><code>calculateAdditionCost()</code> — Aggregate addition pricing</li><li><code>calculateEmblemCost()</code> — Aggregate emblem pricing</li></ul><h4 id="design-control" tabindex="-1">Design Control <a class="header-anchor" href="#design-control" aria-label="Permalink to &quot;Design Control&quot;">​</a></h4><ul><li><code>resetDesign()</code> — Clear all content back to defaults</li><li><code>setEditingObject(obj)</code> — Set active editing target</li><li><code>toggleViewMode()</code> — Switch 2D/3D</li><li><code>setProjectMeta({ projectId, title })</code> — Track saved project</li></ul><hr><h2 id="pricing-engine" tabindex="-1">Pricing Engine <a class="header-anchor" href="#pricing-engine" aria-label="Permalink to &quot;Pricing Engine&quot;">​</a></h2><h3 id="architecture" tabindex="-1">Architecture <a class="header-anchor" href="#architecture" aria-label="Permalink to &quot;Architecture&quot;">​</a></h3><p>Pricing data comes from XML files in <code>/public/xml/</code>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/xml/au_EN/motifs-engraved.xml    → Motif pricing (engraved)</span></span>
<span class="line"><span>/xml/au_EN/motifs-laser.xml       → Motif pricing (laser)</span></span>
<span class="line"><span>/xml/au_EN/motifs-bronze.xml      → Motif pricing (bronze)</span></span>
<span class="line"><span>/xml/en_EN/images.xml             → Image pricing</span></span>
<span class="line"><span>Product catalog XMLs              → Base product + inscription pricing</span></span></code></pre></div><h3 id="price-formula" tabindex="-1">Price Formula <a class="header-anchor" href="#price-formula" aria-label="Permalink to &quot;Price Formula&quot;">​</a></h3><p>XML defines formulas like <code>&quot;136.90+0($q-1)&quot;</code>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>base + rate × (quantity - threshold)</span></span></code></pre></div><p>Where <code>quantity</code> varies by item type:</p><ul><li><strong>Inscriptions</strong>: Number of characters</li><li><strong>Motifs</strong>: Height in mm</li><li><strong>Images</strong>: Width + Height (or Width × Height, depending on model)</li><li><strong>Additions</strong>: Fixed price per size variant</li></ul><h3 id="pricing-files" tabindex="-1">Pricing Files <a class="header-anchor" href="#pricing-files" aria-label="Permalink to &quot;Pricing Files&quot;">​</a></h3><table tabindex="0"><thead><tr><th>File</th><th>Purpose</th></tr></thead><tbody><tr><td><code>lib/motif-pricing.ts</code></td><td>Parse motif XML; calculate by height, color, product type</td></tr><tr><td><code>lib/image-pricing.ts</code></td><td>Parse image XML; calculate by dimensions and color mode (BW/Color/Sepia)</td></tr><tr><td><code>lib/xml-parser.ts</code></td><td>Generic XML catalog parser; <code>calculatePrice(priceModel, quantity)</code></td></tr><tr><td><code>lib/check-price-utils.ts</code></td><td>Material display names; shape name generation</td></tr></tbody></table><h3 id="special-pricing-rules" tabindex="-1">Special Pricing Rules <a class="header-anchor" href="#special-pricing-rules" aria-label="Permalink to &quot;Special Pricing Rules&quot;">​</a></h3><ul><li><strong>Laser products</strong>: Motifs are free (included in base price)</li><li><strong>Gold/Silver gilding</strong>: Premium pricing tier</li><li><strong>Bronze applications</strong>: Separate price model from engraved/laser</li></ul><hr><h2 id="secondary-store-sceneoverlaystore" tabindex="-1">Secondary Store: <code>sceneOverlayStore</code> <a class="header-anchor" href="#secondary-store-sceneoverlaystore" aria-label="Permalink to &quot;Secondary Store: \`sceneOverlayStore\`&quot;">​</a></h2><p>Manages floating overlay panel state:</p><table tabindex="0"><thead><tr><th>State</th><th>Type</th><th>Purpose</th></tr></thead><tbody><tr><td><code>open</code></td><td><code>boolean</code></td><td>Panel visibility</td></tr><tr><td><code>title</code></td><td><code>string</code></td><td>Panel header text</td></tr><tr><td><code>content</code></td><td><code>ReactNode</code></td><td>Panel body content</td></tr><tr><td><code>pos</code></td><td><code>{ x, y }</code></td><td>Panel position (draggable)</td></tr><tr><td><code>collapsed</code></td><td><code>boolean</code></td><td>Collapsed/expanded state</td></tr></tbody></table><hr><h2 id="data-flow-diagram" tabindex="-1">Data Flow Diagram <a class="header-anchor" href="#data-flow-diagram" aria-label="Permalink to &quot;Data Flow Diagram&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>User Interaction (click, drag, form input)</span></span>
<span class="line"><span>         │</span></span>
<span class="line"><span>         ▼</span></span>
<span class="line"><span>  Zustand Store Action (e.g., addMotif, updateInscription)</span></span>
<span class="line"><span>         │</span></span>
<span class="line"><span>         ▼</span></span>
<span class="line"><span>  Store State Update (immutable, via Immer-style)</span></span>
<span class="line"><span>         │</span></span>
<span class="line"><span>    ┌────┼────────────────────┐</span></span>
<span class="line"><span>    ▼    ▼                    ▼</span></span>
<span class="line"><span>  React UI    Three.js Scene    Pricing Engine</span></span>
<span class="line"><span>  (re-render  (re-render mesh,  (recalculate</span></span>
<span class="line"><span>   panels)     textures, text)   costs)</span></span></code></pre></div>`,68)])])}const u=t(i,[["render",c]]);export{m as __pageData,u as default};
